// src/server.js
const http = require('http');
const app = require('./app');

const server = http.createServer(app);

module.exports = app;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = [];

async function getAllProjects() {
  return projectsStore.slice();
}

async function getProjectById(projectId) {
  return projectsStore.find(p => p.id === projectId);
}

async function createProject(name) {
  const project = { id: randomUUID(), name };
  projectsStore.push(project);
  return project;
}

module.exports = {
  getAllProjects,
  getProjectById,
  createProject,
};

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const tasksStore = [];

async function getTasksByProjectId(projectId, status) {
  let tasks = tasksStore.filter(t => t.projectId === projectId);
  if (status) {
    tasks = tasks.filter(t => t.status === status);
  }
  return tasks;
}

async function createTask(projectId, description) {
  const task = { id: randomUUID(), projectId, description, status: 'todo' };
  tasksStore.push(task);
  return task;
}

async function updateTaskStatus(projectId, taskId, status) {
  const task = tasksStore.find(t => t.projectId === projectId && t.id === taskId);
  if (task) {
    task.status = status;
  }
  return task;
}

module.exports = {
  getTasksByProjectId,
  createTask,
  updateTaskStatus,
};

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const membersStore = [];

async function addMember(projectId, userId, role) {
  const member = { id: randomUUID(), projectId, userId, role };
  membersStore.push(member);
  return member;
}

module.exports = {
  addMember,
};

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const commentsStore = [];

async function addComment(projectId, taskId, content) {
  const comment = { id: randomUUID(), projectId, taskId, content };
  commentsStore.push(comment);
  return comment;
}

module.exports = {
  addComment,
};

// src/lib/errors.js
function sendError(res, statusCode, errorCode, message) {
  res.status(statusCode).json({ error: { code: errorCode, message } });
}

module.exports = {
  sendError,
};

const { randomUUID } = require('crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
